import Ariadne
from ariadne import QueryType, MutationType, ObjectType, Field
from ariadne.contrib.auth import current_user

# Define the User and Post types
User = ObjectType("User")
Post = ObjectType("Post")

# Define the query to fetch user profiles
query = QueryType()
query.set_field("users", [User])

# Define the mutation to create a new post
mutation = MutationType()
mutation.set_field("createPost", Post)

# Define the resolvers for the query and mutation
@query.field("users")
def resolve_users(_, info):
    # Fetch all users from the database
    users = [
        {
            "id": 1,
            "username": "johndoe",
            "bio": "I am John Doe"
        },
        {
            "id": 2,
            "username": "janedoe",
            "bio": "I am Jane Doe"
        }
    ]
    return users

@mutation.field("createPost")
def resolve_create_post(_, info, title, content):
    # Create a new post in the database
    post = {
        "id": 1,
        "title": title,
        "content": content
    }
    return post

# Define the schema for the GraphQL API
schema = Ariadne.Schema(query=query, mutation=mutation)

# Define the middleware to handle authentication
def auth_middleware(request):
    # Set the current user based on the request headers
    current_user = request.headers.get("X-User")
    return current_user

# Create a GraphQL API using Ariadne and the defined schema, middleware, and resolvers
api = Ariadne.API(schema=schema, middleware=[auth_middleware])